141→/**
142→ * Classify text using TF-IDF scoring
143→ */
144→function classifyWithTfIdfMethod(text: string): ClassificationResult {
145→  const startTime = Date.now();
146→
147→  try {
148→    const title = extractTitle(text);
149→    const allSuggestions = classifyWithTfIdf(text);
150→
151→    // Filter to top suggestions (max 2 per category with confidence >= 0.3)
152→    const suggestions: Array<TagSuggestion> = [];
153→    const counts = { season: 0, cuisine: 0, "food-category": 0 };
154→
155→    for (const suggestion of allSuggestions) {
156→      if (counts[suggestion.category] < 2 && suggestion.confidence >= 0.3) {
157→        suggestions.push(suggestion);
158→        counts[suggestion.category]++;
159→      }
160→    }
161→
162→    return {
163→      title,
164→      suggestions,
165→      processingTimeMs: Date.now() - startTime,
166→    };
167→  } catch (error) {
168→    console.error("[Text Classifier] TF-IDF classification failed:", error);
169→    return {
170→      title: extractTitle(text),
171→      suggestions: [],
172→      processingTimeMs: Date.now() - startTime,
173→    };
174→  }
