177→/**
178→ * Classify text and extract recipe metadata
179→ */
180→export async function classifyText(
181→  text: string,
182→  method: ClassificationMethod = "embeddings"
183→): Promise<ClassificationResult> {
184→  const startTime = Date.now();
185→
186→  try {
187→    // Use TF-IDF if requested
188→    if (method === "tfidf") {
189→      return classifyWithTfIdfMethod(text);
190→    }
191→
192→    // Use embeddings (default)
193→    // Try to initialize worker if not already done
194→    if (!worker && !workerReady) {
195→      initializeWorker();
196→    }
197→
198→    // If worker is available, classify (worker also extracts semantic title)
199→    if (worker && workerReady) {
200→      const result = await classifyWithWorker(text);
201→      return {
202→        title: result.title ?? extractTitle(text),
203→        suggestions: result.suggestions,
204→        processingTimeMs: Date.now() - startTime,
205→      };
206→    }
207→
208→    // Worker not available, fall back to heuristic title only
209→    console.warn(
210→      "[Text Classifier] Worker not available, returning title only"
211→    );
212→    return {
213→      title: extractTitle(text),
214→      suggestions: [],
215→      processingTimeMs: Date.now() - startTime,
216→    };
217→  } catch (error) {
218→    console.error("[Text Classifier] Classification failed:", error);
219→    return {
220→      title: extractTitle(text),
221→      suggestions: [],
222→      processingTimeMs: Date.now() - startTime,
223→    };
224→  }
